var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRINCIPAL_NPC_CHILD_A","text":{"KOREA":"우리 역시 창칼로 우리가 옳다고 믿는 뜻을 관철하는 자들이다.","JPN":"我々も槍や剣を持ち、我々が正しいと信じた意思を貫く者たちだ。","ENG":"In the end, we too use our blades for the sake of what we believe to be right.","TWN":"我們也是用刀劍貫徹我們信念的人。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_CHILD"},{"id":"L3_1","type":"dialog","speaker":"PRINCIPAL_NPC_CHILD_A","text":{"KOREA":"그러니 나를 넘어서 가라.","JPN":"だからこれ以上進むのならば、私を越えて行きたまえ。","ENG":"So if you must go, go through me.","TWN":"所以，超越我吧。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRINCIPAL_NPC_CHILD_A","text":{"KOREA":"이 너머에, 그대가 진정으로 옳다고 믿는 길이 있다면!","JPN":"この向こうに、君が心から正しいと信じる道があるのなら。","ENG":"If the path you truly believe is right lies beyond here, that is!","TWN":"如果你真的堅信，正確的道路就在我後方的話！"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRINCIPAL_NPC_CHILD_B","text":{"KOREA":"광대라는 기록은 데이터베이스에서 삭제해야겠군! 이래서 휴먼들의 평은 신뢰할 수가 없어!","JPN":"道化という記録はデータベースから削除しなければなりませんね。これだからヒューマンの評価は信頼できません。","ENG":"I should delete your description of being a clown from my database! This is why I find human assessment of each other so unreliable!","TWN":"看來要從資料庫刪除你是個小丑的記錄。所以我就說，不能信賴人類的評價！"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저건…… 뭘 하는 거지?","JPN":"あれは……何だ？","ENG":"What... on earth are they doing?","TWN":"那個是……你在做什麼呢？"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"호라이즌 언니가 보여준 <color=#ffd34c>호라이즌 명작선</color>을 따라하는 거예요.","JPN":"ホライズンお姉ちゃんが見せてくれた<color=#ffd34c>ホライズン名作選</color>の真似です。","ENG":"They're reenacting <color=#ffd34c>Horizon's Greatest Hits</color> that Horizon showed them.","TWN":"我在模仿地平線姊姊展示的<color=#ffd34c>地平線名著選</color>。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"언니가 여기 오실 때면 굉장한 걸 보여주겠다면서 여러 영상을 보여주시거든요.","JPN":"お姉ちゃんはここに来るたびに、すごいものがあるって色んな動画を見せてくれるんです。","ENG":"Every time she visits, she plays a bunch of videos saying she's gonna show something epic.","TWN":"姊姊來的時候，總是給我看各種影片，說要給我看一些很厲害的東西。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"레이첼 언니는 애들한테 뭘 그런 걸 보여주냐며 화내지만, 넷튜브보다 흥미진진해서 애들한테 인기가 많아요.","JPN":"レイチェルお姉ちゃんは子どもたちに見せるものじゃないって怒るけど、ネットチューブよりも面白いから大人気なんですよ。","ENG":"Rachel always scolds her for showing the kids stuff like that, but they find it way more fun than NetTube.","TWN":"雖然瑞秋姊姊總是生氣地說不應該給孩子們看這些東西，但比起網路劇，這些內容更有趣，所以很受孩子們歡迎。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"저는 특히, 기사님이 버고 소드로 땅을 가르는 장면이 인상깊었어요!","JPN":"私は特に、騎士様がヴァルゴソードで大地を切り裂く場面が印象的でした！","ENG":"Personally, I loved the scene where you split the ground with the Virgo Sword!","TWN":"我尤其對騎士用巨劍劈開大地的場景印象深刻！"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……그게 용케 나인 걸 알아챘군.","JPN":"……よく私だとわかったな。","ENG":"...So you figured out it was me.","TWN":"……原來你能察覺到那是我啊。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"저, 저도 처음엔 긴가민가했는데, 원장님 도움으로 기사님을 옮기던 도중 태스크포스 명함을 발견했거든요","JPN":"わ、私も最初は自信なかったけど、院長先生のお手伝いで騎士様を運んでたら、タスクフォースの名刺を見つけて。","ENG":"I-I wasn't sure at first, but while we were helping move you, the headmaster and I found your TASKFORCE card.","TWN":"我，我一開始也半信半疑，但在院長的幫助下移動騎士時發現了特遣勢力的名片。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"죄송해요! 소지품을 뒤지려던 건 아니었어요!","JPN":"すみません！　持ち物を漁るつもりじゃなかったんです！","ENG":"I'm sorry! I wasn't trying to snoop through your stuff!","TWN":"很抱歉！我不是故意要翻你東西的！"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"괜찮다. 도움을 받은 건 내 쪽이니까.","JPN":"問題ない。助けてもらったのはこちらの方だ。","ENG":"It's fine. I'm the one who owes you.","TWN":"沒關係，因為是我這邊得到了幫助。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"진료비는…….","JPN":"治療代は……","ENG":"As for the medical bill...","TWN":"醫療費用是……"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"됐습니다. 딱히 돈을 바라고 한 일이 아니에요.","JPN":"いいんです。別にお金が欲しくて助けたわけではありません。","ENG":"No need. I didn't do it for money.","TWN":"好了。我並不是為了錢才做這件事的。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"기사단이야말로 비용 문제로 의뢰를 넣지 못하는 난민지구에 무상으로 도움을 주는 태스크포스잖습니까.","JPN":"騎士団こそ、生活が貧しくて依頼が出せない難民地区を無償で助けてくれるタスクフォースではありませんか。","ENG":"Your Order helps the refugee districts for free because they can't afford requests. That's what TASKFORCEs like yours do, right?","TWN":"騎士團才是那個在難民區因為費用問題無法委託的地方提供免費幫助的特遣勢力啊。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"원장님! 오셨어요?","JPN":"先生！　おかえりなさい！","ENG":"Headmaster! You're back?","TWN":"院長！你來了？"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"그래. 나 없는 동안 말썽 안 부렸지?","JPN":"ああ、私のいない間大人しくしてたかい？","ENG":"Yes. You kids didn't cause trouble while I was gone, did you?","TWN":"對。我不在的時候沒有惹麻煩吧？"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"죄송합니다. 쟤들은 병원에 입원한 저희 보육원 소속 꼬맹이들인데.","JPN":"すみません。この子たちは病院に入院しているうちの施設の子なのです。","ENG":"My apologies. Those are our orphanage kids who are currently hospitalized.","TWN":"對不起，他們是我們孤兒院的院童。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"기사님을 보고 싶다고 하도 칭얼대는 바람에, 어쩌다 보니 여기서 소란을 피우네요.","JPN":"騎士様に会いたいとせがまれて連れてきましたが、騒がしくしてしまいましたね。","ENG":"They kept begging to see you, so things got a little loud over here.","TWN":"因為一直吵著說想見騎士，結果不知不覺就在這裡鬧起來了。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……저 많은 아이들을 혼자서 돌보고 있는 겁니까?","JPN":"……こんなたくさんの子どもを、一人で世話しているのですか？","ENG":"...Are you taking care of all of them on your own?","TWN":"……你一個人照顧那麼多孩子嗎？"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"죽으면 끝인데 돈 모아서 어디다 쓰겠습니까? 애들이 건강하게만 자라면 그만이죠.","JPN":"死んだら終わりなのに、お金なんて集めても仕方がないでしょう。子どもたちが元気に育ってくれれば、それ以上嬉しいことはありません。","ENG":"Can't take it with you, so why save money? All that matters is they grow up healthy.","TWN":"死了就結束了，攢那麼多錢有什麼用呢？只要孩子們健康成長就好了。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"투자받은 목돈도 있으니, 기사님이 신경 쓰실 필요 없습니다.","JPN":"それに、投資してもらった資金もありますし、心配いりませんよ。","ENG":"We've got some investment funds too, so don't worry about it.","TWN":"我們有投資的大筆資金，你不需要操心。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRINCIPAL_NPC_CHILD_A","text":{"KOREA":"있지, 누나! 누나랑 호라이즌이랑 싸우면 진짜 호라이즌이 이겨?","JPN":"ねえ、お姉ちゃん！　お姉ちゃんとホライズンが戦ったら本当にホライズンが勝つの？","ENG":"Miss! If you and Horizon got in a real fight, would she win?","TWN":"那個，姊姊！如果姊姊和地平線打架的話，真的會是地平線贏嗎？"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRINCIPAL_NPC_CHILD_B","text":{"KOREA":"나도 궁금해! 맨날 호라이즌은 자기가 제대로 안 싸워서 밀린 것처럼 보인 거래!","JPN":"私も気になる！　ホライズンはいつも、本気出してないから負けてるように見えるんだって！","ENG":"Yeah! She always says she was holding back last time!","TWN":"我也很好奇！每天都聽說是因為地平線自己沒好好戰鬥才被打敗的！"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"으, 응?","JPN":"う、うん？","ENG":"H-huh?","TWN":"嗯，嗯？"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"욘석들! 기사님 불편하시니 대화는 자제하라고 했어, 안 했어?","JPN":"こら！　騎士様が困るからしつこく話しかけないようにと言ったじゃないか！","ENG":"You rascals! Didn't I tell you to behave and not bother her?","TWN":"你們這幫傢伙！我是不是說過，騎士姊姊不舒服，別再說話了？"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRINCIPAL_NPC_CHILD_A","text":{"KOREA":"치사해요! 엠마는 아까부터 대화했는데!","JPN":"ずるい！　エマはさっきから話してるのに！","ENG":"That's not fair! Emma's been talking the whole time!","TWN":"真不公平！艾瑪從剛才就一直在說話！"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"엠마는 원장님 도와줬으니 괜찮다. 원래 착한 일을 하면 보답을 받는 거야.","JPN":"エマは私を手伝ってくれたからいいんだ。いい子にはご褒美があるものだからね。","ENG":"Emma helped me out, so she's allowed to. Good deeds get rewarded.","TWN":"艾瑪幫助了院長，所以沒關係。做好事總會有回報的。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"그러니 기사님 사인받고 싶으면 어떻게 해야 돼?","JPN":"だから、騎士様にサインしてもらいたいなら、どうすればいいと思う？","ENG":"So if you want her autograph, what should you do?","TWN":"那麼如果想要騎士姊姊的簽名，該怎麼做呢？"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"원장님 말 잘 들어야 해요!","JPN":"先生のいうことをちゃんと聞く！","ENG":"Listen to the Headmaster!","TWN":"要好好聽院長的話喔！"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"그래. 알았으면 다들 얌전히 놀고 있어.","JPN":"そう。わかったなら、みんな大人しくしてなさい。","ENG":"Exactly. Now, behave and play nicely, all of you.","TWN":"好吧。大家乖乖玩耍吧。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"죄송합니다. 애들이 워낙 천방지축이라 멋대로 기사님을 팔아버렸네요.","JPN":"すみません。子どもたちがあまりに騒ぐので、勝手に騎士様の名前を借りてしまいました。","ENG":"Apologies again. The kids got a little too excited, so I kind of dragged you into it.","TWN":"抱歉，孩子們實在太調皮了，竟然擅自把你給賣了。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그건 괜찮습니다만…….","JPN":"それはいいですが……","ENG":"It's all right...","TWN":"那倒沒關係……"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"아, 몸 때문에 그러시나요? 의사 말로는 큰 상처는 아니니 너무 걱정할 필요 없답니다.","JPN":"あ、お体のことですか。医者の話では、深刻な傷ではないので心配せずともよいとのことでした。","ENG":"Oh, is it your injury? The doctor said it's not too serious, so you don't need to worry.","TWN":"啊，是因為身體嗎？醫生說不是大傷，不用太擔心。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"처음에는 잘못되는 거 아닌가 싶었는데, 역시 카운터가 대단하긴 한가 봅니다.","JPN":"最初は危ないのではと焦りましたが、さすがカウンターは違いますね。","ENG":"I was worried at first, but I guess Counters really are something else.","TWN":"一開始我還以為會出問題，看來制裁者果然很厲害啊。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그게 아니라, 조금 당황해서 그렇습니다.","JPN":"そうではなくて、少し意外で。","ENG":"It's not that. I'm just surprised.","TWN":"不是這樣的，只是有點慌張罷了。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아이들이라도 최근 일로 저를 멀리할 줄 알았거든요.","JPN":"子どもたちも、最近の件で私を警戒すると思っていました。","ENG":"I thought even kids would be avoiding me after everything that happened.","TWN":"我以為即使是孩子們也會因為最近的事情而疏遠我。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":""}}}},{"id":"L3_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"최근 일이라면 넷튜브에 올라온 영상 말하시는 건가요?","JPN":"最近の件というと、ネットチューブに上がっているあの動画のことですか？","ENG":"You mean the videos going around on NetTube?","TWN":"最近的事情是指上傳到網路的影片嗎?"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"저흰 그런 거 안 믿어요. 조디악 나이츠는 민중을 수호하는 멋진 기사님들이잖아요.","JPN":"そんなもの、私たちは信じません。ゾディアックナイツは民衆を守護する立派な騎士たちではありませんか。","ENG":"We don't believe those. The Zodiac Knights are the coolest protectors of the people.","TWN":"我們不相信那些。十二宮騎士是守護民眾的帥氣騎士們啊。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"예전에 오셨던 기사님도…….","JPN":"以前お越しになった騎士様も……","ENG":"Even the knight who visited us before–","TWN":"以前來的騎士也……"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>샤레이드 도시관리국에서 알립니다.</color>","JPN":"<color=#ffd34c>シャレード都市管理局からお知らせします。</color>","ENG":"<color=#ffd34c>This is an announcement from Charade City Management.</color>","TWN":"<color=#ffd34c>查雷德城市管理局的通知。</color>"},"stage":{"bg":"ROOFTOP2","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재, 도심 일부 지역에 침식파 밀도가 급격히 상승하고 있습니다.</color>","JPN":"<color=#ffd34c>現在、都市中心部の一部の地域において侵食波密度が急激に上昇しています。</color>","ENG":"<color=#ffd34c>Currently, Corruption ray levels are rapidly rising in some areas of the city.</color>","TWN":"<color=#ffd34c>目前市中心部分區域的侵蝕波密度急速增加。</color>"},"stage":{"bg":"ROOFTOP2","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재 추세로 볼 때, 곧 급성 침식 경보가 발령될 예정입니다.</color>","JPN":"<color=#ffd34c>現在の状況から、まもなく急性侵食警報が発令される見込みです。</color>","ENG":"<color=#ffd34c>Given the current trend, an acute Corruption alert may be issued soon.</color>","TWN":"<color=#ffd34c>照目前的情勢看來，很快就會發布緊急侵蝕警報<。/color>"},"stage":{"bg":"ROOFTOP2","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"뭐, 뭐야. 샤레이드 한 가운데서 침식 현상이라고?","JPN":"な、何だ？　シャレードの真ん中で侵食現象？","ENG":"Huh? A Counterside Effect in the middle of Charade?","TWN":"什、什麼啊。在查雷德的中心發生侵蝕現象？"},"stage":{"bg":"ROOFTOP2","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_SIREN_02"},{"id":"L12_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"이게 대체 어떻게 된 거야?","JPN":"いったい何がどうなっているんだ？","ENG":"What is happening?","TWN":"這到底是怎麼回事？"},"stage":{"bg":"ROOFTOP2","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"워, 원장님. 저기 보세요!","JPN":"せ、先生。あそこを見てください！","ENG":"H-Headmaster! Look over there!","TWN":"哇，院長。看那邊！"},"stage":{"bg":"ROOFTOP2","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"아니, 뭔 침식체가 도로 한가운데에 있어?!","JPN":"は、はあ！？　道のど真ん中に侵食体？","ENG":"What? C.O.s in the middle of the street?!","TWN":"什麼，為什麼侵蝕體會在馬路中央？！"},"stage":{"bg":"ROOFTOP2","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"너희들! 당황하지 말고 우선 침착하게…….","JPN":"みんな、慌てずに、落ち着いて……","ENG":"Kids! Don't panic, stay calm and...","TWN":"你們！不要慌張，先冷靜下來……"},"stage":{"bg":"ROOFTOP2","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"아니, 너네 왜 태연하냐?","JPN":"って、なんで平然としているんだ？","ENG":"Wait, why are you all so calm?","TWN":"為什麼你們這麼淡定？"},"stage":{"bg":"ROOFTOP2","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRINCIPAL_NPC_CHILD_A","text":{"KOREA":"에이. 기사님이 있는데 무슨 상관이에요?","JPN":"だって、騎士様がいるじゃないですか！","ENG":"Come on. A knight's right here, isn't she?","TWN":"哎。有騎士在有什麼關係呢？"},"stage":{"bg":"ROOFTOP2","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCIPAL_NPC_CHILD_B","text":{"KOREA":"맞아요! 침식체 같은 건 한 주먹거리도 안 돼요!","JPN":"そうです！　侵食体なんか一発で倒されますよ！","ENG":"Yeah! C.O.s don't stand a chance!","TWN":"沒錯！侵蝕體什麼的根本不值一提！"},"stage":{"bg":"ROOFTOP2","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"욘석들아! 방금 전까지 쓰러져 계셨던 분한테 그게 무슨 민폐야?","JPN":"こら！　さっきまで倒れていた方に迷惑だろう！","ENG":"You troublemakers! Don't you remember she was just in the hospital!?","TWN":"你們這幫傢伙！剛才還倒在地上的人，你們這樣太過分了吧？"},"stage":{"bg":"ROOFTOP2","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"죄송합니다, 기사님. 저놈들은 제가 타이를게요.","JPN":"すみません。子どもたちは後で叱っておきます。","ENG":"I'm so sorry. I'll scold them properly.","TWN":"對不起，騎士大人，我會好好教訓那些傢伙的。"},"stage":{"bg":"ROOFTOP2","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……아뇨. 몸풀기로는 적당한 상대 같군요.","JPN":"……いいえ、肩慣らしにはちょうどいい相手です。","ENG":"...No need. C.O.s might be just the warm-up I need.","TWN":"……不。作為熱身，這個對手還算合適。"},"stage":{"bg":"ROOFTOP2","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"관리국의 지원이 올때까지 시간을 벌 필요도 있어 보이고요.","JPN":"管理局の支援が来るまで時間を稼ぐ必要もありそうですし。","ENG":"And we should buy time until the Administration sends backup.","TWN":"看起來我們需要拖延時間，直到管理局的支援到來。"},"stage":{"bg":"ROOFTOP2","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"근방 침식체들은 제가 정리하겠습니다.","JPN":"近くの侵食体は私が片付けます。","ENG":"I'll take care of the C.O.s in the area.","TWN":"我會處理附近的侵蝕體。"},"stage":{"bg":"ROOFTOP2","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제가 돌아올 때까지 아이들을 부탁합니다.","JPN":"帰ってくるまで、子どもたちのことをお願いします。","ENG":"Keep the children safe until I return.","TWN":"在我回來之前，請照顧好孩子們。"},"stage":{"bg":"ROOFTOP2","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};